 25→export function createFloor(name = 'Floor', levelIndex = 0, options = {}) {
 26→  const floorToFloorHeight = options.floorToFloorHeight ?? WALL_HEIGHT;
 27→  const elevation = options.elevation ?? (levelIndex * floorToFloorHeight);
 28→
 29→  return {
 30→    id: generateId('floor'),
 31→    name,
 32→    levelIndex,
 33→    elevation,
 34→    floorToFloorHeight,
 35→    walls: [],
 36→    rooms: [],
 37→    doors: [],
 38→    windows: [],
 39→    columns: [],
 40→    beams: [],
 41→    stairs: [],
 42→    landings: [],
 43→    fixtures: [],
 44→    annotations: [],
 45→    annotationSettings: createAnnotationSettings(),
 46→    slabs: [],
 47→    sectionCuts: [],
 48→    railings: [],
 49→  };
 50→}
 51→
 52→export function nextSectionLabel(existingCuts = []) {
 53→  const usedLetters = new Set(
 54→    existingCuts
 55→      .map(c => {
 56→        const match = c.label?.match(/^Section\s+([A-Z])-\1$/);
 57→        return match ? match[1] : null;
 58→      })
 59→      .filter(Boolean)
 60→  );
 61→  for (let i = 0; i < 26; i++) {
 62→    const letter = String.fromCharCode(65 + i);
 63→    if (!usedLetters.has(letter)) return `Section ${letter}-${letter}`;
 64→  }
 65→  return `Section ${existingCuts.length + 1}`;
 66→}
