232→export function createRoom(name = 'Room', points = [], color = ROOM_COLOR) {
233→  const area = polygonArea(points);
234→  const centroid = points.length >= 3 ? polygonCentroid(points) : { x: 0, y: 0 };
235→  return {
236→    id: generateId('room'),
237→    name,
238→    points: points.map(p => ({ x: p.x, y: p.y })),
239→    labelPosition: { ...centroid },
240→    color,
241→    area,
242→  };
243→}
