 88→export function snapToGrid(value, grid = SHEET_TOKENS.viewportGrid) {
 89→  return Math.round(value / grid) * grid;
 90→}
 91→
 92→export function snapRectToGrid(rect, grid = SHEET_TOKENS.viewportGrid) {
 93→  return {
 94→    x: snapToGrid(rect.x, grid),
 95→    y: snapToGrid(rect.y, grid),
 96→    width: Math.max(grid, snapToGrid(rect.width, grid)),
 97→    height: Math.max(grid, snapToGrid(rect.height, grid)),
 98→  };
 99→}
