101→export function formatSheetDate(value) {
102→  if (!value) return '';
103→  const date = new Date(value);
104→  if (Number.isNaN(date.getTime())) return String(value);
105→  const year = date.getFullYear();
106→  const month = String(date.getMonth() + 1).padStart(2, '0');
107→  const day = String(date.getDate()).padStart(2, '0');
108→  return `${year}-${month}-${day}`;
109→}
