 25→function getSheetPreviewCacheKey(source) {
 26→  return [
 27→    source?.project?.id || 'project',
 28→    source?.project?.updatedAt || 'snapshot',
 29→    source?.activeFloorId || 'all',
 30→    SHEET_PREVIEW_OPTIONS.width,
 31→    SHEET_PREVIEW_OPTIONS.height,
 32→    SHEET_PREVIEW_OPTIONS.preset,
 33→  ].join(':');
