 36→function renderSheetPreviewImage(source) {
 37→  const cacheKey = getSheetPreviewCacheKey(source);
 38→  if (!sheetPreviewCache.has(cacheKey)) {
 39→    sheetPreviewCache.set(cacheKey, import('@/three/viewer/renderToImage')
 40→      .then(({ renderSceneToImage }) => {
 41→        const imageUrl = renderSceneToImage(source.project, {
 42→          activeFloorId: source.activeFloorId,
 43→          width: SHEET_PREVIEW_OPTIONS.width,
 44→          height: SHEET_PREVIEW_OPTIONS.height,
 45→          preset: SHEET_PREVIEW_OPTIONS.preset,
 46→        });
 47→
 48→        return imageUrl
 49→          ? { status: 'ready', imageUrl }
 50→          : { status: 'empty', imageUrl: null };
 51→      })
 52→      .catch((error) => {
 53→        sheetPreviewCache.delete(cacheKey);
 54→        throw error;
 55→      }));
 56→  }
 57→
 58→  return sheetPreviewCache.get(cacheKey);
 59→}
