15→export function renderSceneToImage(project, options = {}) {
16→  const {
17→    activeFloorId = null,
18→    width = 1600,
19→    height = 1000,
20→    preset = 'plan_aligned',
21→  } = options;
22→
23→  const sceneDescriptor = buildPreviewScene(project, { activeFloorId });
24→  if (!sceneDescriptor.hasVisibleObjects) return null;
25→
26→  const materialPalette = createMaterialPalette();
27→  const scene = new THREE.Scene();
28→  scene.background = new THREE.Color(0xf5f7fa);
29→
30→  const camera = new THREE.PerspectiveCamera(42, width / height, 10, 100000);
31→  const renderer = new THREE.WebGLRenderer({
32→    antialias: true,
33→    alpha: false,
34→    preserveDrawingBuffer: true,
35→  });
36→  renderer.outputColorSpace = THREE.SRGBColorSpace;
37→  renderer.setPixelRatio(1);
38→  renderer.setSize(width, height);
39→
40→  scene.add(new THREE.AmbientLight(0xffffff, 0.72));
41→  scene.add(new THREE.HemisphereLight(0xdde7f4, 0xe6ded0, 0.7));
42→  const keyLight = new THREE.DirectionalLight(0xffffff, 1.05);
43→  keyLight.position.set(3500, 5000, 2000);
44→  scene.add(keyLight);
45→
46→  const root = buildPreviewObjectRoot(sceneDescriptor, materialPalette);
47→  scene.add(root);
48→
49→  const bounds = sceneDescriptor.bounds;
50→  const gridSize = Math.max(bounds.maxX - bounds.minX, bounds.maxY - bounds.minY, 4000);
51→  const normalizedSize = Math.ceil(gridSize / 1000) * 1000;
52→  const divisions = Math.max(8, Math.round(normalizedSize / 500));
53→  const grid = new THREE.GridHelper(normalizedSize, divisions, 0x8fa1b4, 0xc7d1db);
54→  grid.position.y = sceneDescriptor.groundLevel;
55→  grid.material.transparent = true;
56→  grid.material.opacity = 0.45;
57→  scene.add(grid);
58→
59→  const direction = (PRESETS[preset] || PRESETS.plan_aligned).clone().normalize();
60→  const box = new THREE.Box3(
61→    new THREE.Vector3(bounds.minX, bounds.minElevation, bounds.minY),
62→    new THREE.Vector3(bounds.maxX, bounds.maxElevation, bounds.maxY)
63→  );
64→  const size = box.getSize(new THREE.Vector3());
65→  const center = box.getCenter(new THREE.Vector3());
66→  const halfFovY = THREE.MathUtils.degToRad(camera.fov / 2);
67→  const halfFovX = Math.atan(Math.tan(halfFovY) * camera.aspect);
68→  const distanceByHeight = Math.max(size.y, size.z) / (2 * Math.tan(halfFovY));
69→  const distanceByWidth = Math.max(size.x, size.z) / (2 * Math.tan(halfFovX));
70→  const distance = Math.max(distanceByHeight, distanceByWidth, size.length() / 2 * 1.4) * 1.15;
71→
72→  camera.position.copy(center.clone().add(direction.multiplyScalar(distance)));
73→  camera.lookAt(center);
74→  camera.near = Math.max(10, distance / 200);
75→  camera.far = distance * 10;
76→  camera.updateProjectionMatrix();
77→
78→  renderer.render(scene, camera);
79→  const dataUrl = renderer.domElement.toDataURL('image/png');
80→
81→  scene.remove(root);
82→  disposeScene(root, { disposeMaterials: true });
83→  grid.geometry?.dispose?.();
84→  grid.material?.dispose?.();
85→  disposeMaterialPalette(materialPalette);
86→  renderer.dispose();
87→
88→  return dataUrl;
89→}
